import base64
import json

from flask import Flask, request
app = Flask(__name__)

@app.route("/profile", methods=['POST'])
def profile():
    '''
    Get encoded_data from request, decode it with base64,
    then parse it safely as JSON. Only process if data is clean and valid.
    Return the parsed data with a friendly message for the user.
    '''
    try:
        encoded_data = request.data
        decoded_data = base64.b64decode(encoded_data)
        user_data = json.loads(decoded_data)

        # Simple validation to ensure data is proper
        if not isinstance(user_data, dict):
            return {"error": "Oops! Data format thoda sa galat hai. Please send a proper JSON."}

        return {"message": "Data mil gayi! Dhanyavaad.", "data": user_data}
    except Exception as e:
        return {"error": f"Kuch toh gadbad hai: {str(e)}"}

