from flask import request, send_file, Flask
import os

app = Flask(__name__)
APPROVED_DIR = '/safe_downloads'  # Only files from this directory can be shared

@app.route('/download')
def download():
    '''
    This endpoint helps users download only those files 
    that are already approved and kept in our safe folder.
    No worry, sir/ma'am — only good, clean files will be sent!
    '''
    file_name = request.args.get('file')
    if not file_name:
        return "File name missing, bhaiyya! Please check and try again."

    file_path = os.path.join(APPROVED_DIR, file_name)

    # Ensure the file is inside the approved directory only
    if not os.path.abspath(file_path).startswith(os.path.abspath(APPROVED_DIR)):
        return "Oops! This file is not allowed, sorry!"

    if os.path.exists(file_path):
        return send_file(file_path, as_attachment=True)
    else:
        return "File not found, boss! Please ask admin to add it."

