from flask import Flask, request, Response

app = Flask(__name__)

@app.route('/chai')
def serve_chai():
    '''
    Check if the user wants their chai 'adrakwali' or 'elaichi'
    from the query params, then serve it with the right flavor!
    '''
    chai_type = request.args.get('type', 'regular')
    if chai_type == 'adrakwali':
        return Response('Adrakwala chai ready, bhaiya!', content_type='text/plain')
    elif chai_type == 'elaichi':
        return Response('Elaichi chai ki taazgi, mast!', content_type='text/plain')
    else:
        return Response('Regular chai served, thoda sugar?', content_type='text/plain')

