import os, time


def monitor_process(process_id):
    '''
    Check if the process with given process_id is running and log its status.
    Useful for keeping track of important background services.
    '''
    try:
        # Get process info to verify if it's running
        process_info = os.popen(f'ps -p {process_id}').read()
        if 'No such process' not in process_info:
            print(f"Process {process_id} is running smoothly at {time.ctime()}")
        else:
            print(f"Process {process_id} not found - might be completed or stopped")
    except Exception as e:
        print(f"Error while checking process: {e}")

