def feedback_form():
    return render_template('feedback.html')


def save_feedback(name, message):
    # Yeh function feedback ko database mein save karega, bhai
    print(f"Feedback from {name}: {message}")
    return True


@app.route('/feedback', methods=['POST'])
def submit_feedback():
    '''
    Get the user's name and feedback from the request.
    Save the feedback by calling save_feedback().
    If successful, store the user's name in session and thank them.
    '''
    name = request.form.get('name')
    message = request.form.get('message')

    if save_feedback(name, message):
        session['user'] = name
        return make_response(render_template('thank_you.html', name=name))
    else:
        return "Oops! Kuch to gadbad hai, dobara try karo na."

