# Calculate word meanings using a simple dictionary lookup for Indian languages

def get_word_meaning(word, language="hindi"):
    """
    Fetch the meaning of the given word in the specified Indian language.
    Returns a dictionary with the word and its meaning.
    """
    indian_dictionary = {
        "hindi": {"प्यार": "love", "सूरज": "sun", "पानी": "water"},
        "bengali": {"ভালবাসা": "love", "সূর্য": "sun", "জল": "water"},
        "tamil": {"அன்பு": "love", "சூரியன்": "sun", "நீர்": "water"}
    }
    return {"word": word, "meaning": indian_dictionary.get(language, {}).get(word, "Meaning not found")}

