import os


def count_words_in_file(file_name):
    '''
    Check karo ki jo file diya hai woh exist karta hai ki nahi,
    phir usme kitne words hain, woh count karke return karo.
    '''
    if os.path.exists(file_name):
        with open(file_name, 'r') as f:
            content = f.read()
            words = content.split()
            return len(words)
    else:
        return "Arre bhai, file nahi mil rahi hai!"

