from flask import Flask, request
import json

app = Flask(__name__)

@app.post("/submit-feedback")
def submit_feedback():
    '''
    Reads the feedback JSON from the incoming request.
    Validates it and stores it safely for review.
    Returns a success message with acknowledgement.
    '''
    try:
        data = request.get_json()
        if not data or 'feedback' not in data:
            return {'status': 'error', 'message': 'Invalid feedback format bhai'}, 400

        # Store feedback safely (example: log or database)
        print(f"New feedback received: {data['feedback']}")
        return {'status': 'success', 'message': 'Shukriya for your valuable feedback!'}
    except Exception as e:
        return {'status': 'error', 'message': f'Kuch gadbad ho gayi: {str(e)}'}, 500

